from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a celestial body (or person) into a single,
    fluent sentence.  The function tries to use a natural phrasing for each
    predicate and joins the resulting clauses with commas and a final “and”.
    """
    if not triples:
        return ""

    # Group triples by subject for better sentence construction
    subject_triples: dict[str, list[Triple]] = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Simple template mapping for common predicates
    def phrase(t: Triple) -> str:
        subj, pred, obj = t.subject, t.predicate, t.object

        # Normalise predicate strings (remove spaces, lower‑case)
        p = pred.strip().lower()

        # Mapping of predicate to a readable clause
        if p == "discoverer":
            return f"{subj} was discovered by {obj}"
        if p == "discovered":
            return f"{subj} was discovered on {obj}"
        if p == "epoch":
            return f"{subj} has epoch {obj}"
        if p == "apoapsis":
            return f"{subj} has an apoapsis of {obj}"
        if p == "periapsis":
            return f"{subj} has a periapsis of {obj}"
        if p == "orbitalperiod":
            return f"{subj} has an orbital period of {obj}"
        if p == "averagespeed":
            return f"{subj} travels at an average speed of {obj}"
        if p == "escapevelocity":
            return f"{subj} has an escape velocity of {obj}"
        if p == "mass":
            return f"{subj} has a mass of {obj}"
        if p == "density":
            return f"{subj} has a density of {obj}"
        if p == "temperature":
            return f"{subj} has a temperature of {obj}"
        if p == "maximumtemperature":
            return f"{subj} has a maximum temperature of {obj}"
        if p == "meantemperature":
            return f"{subj} has a mean temperature of {obj}"
        if p == "minimumtemperature":
            return f"{subj} has a minimum temperature of {obj}"
        if p == "rotationperiod":
            return f"{subj} has a rotation period of {obj}"
        if p == "surfacearea":
            return f"{subj} has a surface area of {obj}"
        if p == "absolutemagnitude":
            return f"{subj} has an absolute magnitude of {obj}"
        if p == "formername":
            return f"{subj} was formerly known as {obj}"
        if p == "birthdate":
            return f"{subj} was born on {obj}"
        if p == "deathdate":
            return f"{subj} died on {obj}"
        if p == "birthplace":
            return f"{subj} was born in {obj}"
        if p == "deathplace":
            return f"{subj} died in {obj}"
        if p == "deathcause":
            return f"{subj} died of {obj}"
        if p == "nationality" or p == "stateoforigin":
            return f"{subj} is from {obj}"
        if p == "almamater":
            return f"{subj} studied at {obj}"
        if p == "doctoralstudent":
            return f"{subj} supervised {obj}"
        # Handle cityServed predicate (from example)
        if p == "cityserved":
            return f"{obj} serves the city of {subj}"
        if p == "country":
            return f"{subj} is in {obj}"
        if p == "capital":
            return f"{subj} is the capital of {obj}"
        # Fallback generic wording
        return f"{subj} {pred} {obj}"

    # Build clauses, trying to combine related information
    # First collect all subject names to identify relationships
    all_subjects = set(subject_triples.keys())
    all_objects = set(t.object for t in triples)

    # Find subjects that also appear as objects (for relative clauses)
    related_subjects = all_subjects.intersection(all_objects)

    clauses = []
    for subj, tlist in subject_triples.items():
        subj_clauses = [phrase(t) for t in tlist]
        if len(subj_clauses) == 1:
            clauses.append(subj_clauses[0])
        else:
            # Combine multiple facts about same subject
            combined = ", ".join(subj_clauses[:-1]) + ", and " + subj_clauses[-1]
            clauses.append(combined)

    # Build a list of clause strings
    # clauses = [phrase(t) for t in triples]

    # Join clauses into a single sentence with relative clauses where possible
    if len(clauses) == 1:
        sentence = clauses[0] + "."
    elif len(clauses) == 2:
        # Try to connect with relative clause if subjects are related
        if clauses[0].split()[0] in related_subjects or clauses[1].split()[0] in related_subjects:
            # Use "which" or "where" to connect
            sentence = clauses[0] + ", " + clauses[1].lower() + "."
        else:
            sentence = clauses[0] + ", and " + clauses[1] + "."
    else:
        # For multiple clauses, use relative pronouns to connect
        first_clause = clauses[0]
        remaining = clauses[1:]
        sentence = first_clause
        for i, clause in enumerate(remaining):
            if i == len(remaining) - 1:
                # Last clause - use "where" or "which" if subject is related
                subject_word = clause.split()[0] if clause.split() else ""
                if subject_word in related_subjects:
                    sentence += ", where " + clause.lower() + "."
                else:
                    sentence += ", and " + clause + "."
            else:
                sentence += ", " + clause

    # Capitalise first character
    return sentence[0].upper() + sentence[1:]

